/**
 * Sprout Design System — NavigationBar (Bottom Tab Bar)
 *
 * ✅ EXACT MATCH to Figma component "Navigation Bar" (node: 100:8821)
 * Source page: ↪︎ Components · Figma file: EhpRiGZ5eJnBb132X9zewg
 *
 * Key values extracted directly from Figma:
 *   - Background: #F4F1EA (cream = Secondary/500) — NOT white
 *   - Height: 69px (excl. safe area inset)
 *   - Padding top/bottom: 12px each
 *   - 2-layer shadow: large blur + subtle blur
 *   - Tab types confirmed: Home | Memories | AI Assist | Chat | Clubs
 */

import React from 'react';
import {
  StyleSheet,
  Text,
  TouchableOpacity,
  View,
  ViewStyle,
} from 'react-native';

// ─── Raw Figma-extracted values ───────────────────────────────────────────────

const FIGMA = {
  // Background — VariableID:26:516 = Secondary/500 = cream
  background:   '#F4F1EA',

  // Active indicator pill
  activePill:   '#186338',  // brand/500
  pillWidth:    40,
  pillHeight:   3,

  // Tab label — active
  activeLabel:  '#186338',  // brand/500
  activeFont:   'PlayfairDisplay-Medium',
  activeFontWeb:'Playfair Display',
  activeFontWeight: '500' as const,

  // Tab label — inactive
  inactiveLabel:'#7C8C79',  // muted green-grey from Figma
  inactiveFont: 'Inter',
  inactiveFontWeight: '400' as const,

  // Label font size
  labelSize: 10,

  // Dimensions
  barHeight:    69,
  paddingV:     12,   // top and bottom

  // Shadow — 2 layers from Figma effects array:
  //   Layer 1: blur=25, spread=3, offset(4,5), alpha=0.15
  //   Layer 2: blur=10, spread=0, offset(2,5), alpha=0.05
  // React Native only supports one shadow — using the stronger one
  shadowColor:  'rgba(14,14,16,0.15)',
  shadowOffset: { width: 4, height: -3 },
  shadowRadius: 12,
  elevation:    12,
};

// ─── Types ───────────────────────────────────────────────────────────────────

/** Figma tab types: Home | Memories | AI Assist | Chat | Clubs */
export type NavTabKey = 'home' | 'memories' | 'ai-assist' | 'chat' | 'clubs' | string;

export interface NavTab {
  /** Unique key */
  key: NavTabKey;
  /** Label shown below icon (matches Figma tab labels) */
  label: string;
  /** Icon renderer — receives active boolean */
  icon: (active: boolean) => React.ReactNode;
}

export interface NavigationBarProps {
  tabs: NavTab[];
  activeTab: NavTabKey;
  onTabPress: (key: NavTabKey) => void;
  /** Safe area bottom inset — 34px on iPhone, 0 on Android/older iPhone */
  bottomInset?: number;
  style?: ViewStyle;
}

// ─── Component ───────────────────────────────────────────────────────────────

export const NavigationBar: React.FC<NavigationBarProps> = ({
  tabs,
  activeTab,
  onTabPress,
  bottomInset = 34,
  style,
}) => {
  return (
    <View
      style={[
        styles.container,
        {
          backgroundColor: FIGMA.background,  // #F4F1EA cream (from Figma)
          paddingBottom: bottomInset + FIGMA.paddingV,
          paddingTop: FIGMA.paddingV,
          shadowColor:   FIGMA.shadowColor,
          shadowOffset:  FIGMA.shadowOffset,
          shadowRadius:  FIGMA.shadowRadius,
          shadowOpacity: 1,
          elevation:     FIGMA.elevation,
        },
        style,
      ]}
    >
      {tabs.map((tab) => {
        const isActive = tab.key === activeTab;

        return (
          <TouchableOpacity
            key={tab.key}
            style={styles.tab}
            onPress={() => onTabPress(tab.key)}
            activeOpacity={0.7}
            accessibilityRole="tab"
            accessibilityState={{ selected: isActive }}
            accessibilityLabel={tab.label}
          >
            {/* Active indicator pill — 3px × 40px at top */}
            {isActive && (
              <View style={styles.activePill} />
            )}

            {/* Icon */}
            <View style={styles.iconWrapper}>
              {tab.icon(isActive)}
            </View>

            {/* Label */}
            <Text
              style={{
                fontSize:   FIGMA.labelSize,
                lineHeight: FIGMA.labelSize * 1.5,
                color:      isActive ? FIGMA.activeLabel   : FIGMA.inactiveLabel,
                fontFamily: isActive ? FIGMA.activeFontWeb : FIGMA.inactiveFont,
                fontWeight: isActive ? FIGMA.activeFontWeight : FIGMA.inactiveFontWeight,
                letterSpacing: 0.1,
              }}
              numberOfLines={1}
            >
              {tab.label}
            </Text>
          </TouchableOpacity>
        );
      })}
    </View>
  );
};

// ─── Styles ──────────────────────────────────────────────────────────────────

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    alignItems:    'flex-start',
  },
  tab: {
    flex:           1,
    alignItems:     'center',
    justifyContent: 'flex-start',
    paddingTop:     4,
    gap:            4,
    position:       'relative',
  },
  activePill: {
    position:        'absolute',
    top:             -12,   // sits at the very top edge of the bar
    width:           FIGMA.pillWidth,
    height:          FIGMA.pillHeight,
    borderRadius:    9999,
    backgroundColor: FIGMA.activePill,
  },
  iconWrapper: {
    width:           28,
    height:          28,
    alignItems:      'center',
    justifyContent:  'center',
  },
});

export default NavigationBar;
